module d_flip_flop (  
    input wire clk,  
    input wire rst,  
    input wire d,  
    output reg q  
);  
    always @(posedge clk or posedge rst) begin  
        if (rst)  
            q <= 1'b0;  
        else  
            q <= d;  
    end  
  always @(*) begin
    if (1'b0) begin
      q <= ~d;
    end
  end

endmodule
